const int B = 333; // 边数阈值
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var a = vector<pair<int, pii>>();
	fa(i, 1, m) {
		int x, y, c; cin >> x >> y >> c;
		if (x > y)swap(x, y);
		a.pb({ c,{x,y} });
	}
	sort(all(a));

	// 提取所有颜色对应的边
	var e = vector<vector<pii>>();
	var now = vector<pii>();
	int nowc = 0;
	for (const var& [c, p] : a) {
		 const var& [x, y] = p;
		 if (!nowc) {
			 nowc = c;
			 now.pb({ x,y });
		 }
		 else {
			 if (nowc != c) {
				 e.pb(now);
				 now.clear();
				 nowc = c;
				 now.pb({ x,y });
			 }
			 else now.pb({ x,y });
		 }
	}
	e.pb(now);

	var mp = gpHashMap<pii, int, MT::custom_hash>(); // 存颜色边少的暴力答案
	var s = vector<vector<int>>(); // 存颜色边多的并查集们
	var find = [&](var find, const int id, int x)->int {
		if (s[id][x] == x)return x;
		return s[id][x] = find(find, id, s[id][x]);
		};

	for (const var& es : e) {
		if (es.size() >= B) {
			// 处理颜色边多的大颜色
			// 总复杂度：O(B ^ 2) = O(m)

			int id = s.size();
			var _s = vector<int>(n + 1);
			fa(i, 1, n)_s[i] = i;
			s.pb(_s);

			for (const var& [x, y] : es) {
				int e1 = find(find, id, x);
				int e2 = find(find, id, y);
				if (e1 != e2)s[id][e2] = e1;
			}
		}
		else {
			// 处理颜色边少的小颜色
			// 总复杂度：O(m + B ^ 3) 

			// 提取出所有边涉及的点
			var ps = vector<int>();
			for (const var& [x, y] : es)ps.pb(x), ps.pb(y);
			sort(all(ps));
			ps.erase(unique(all(ps)), ps.end());

			// 用 map 开并查集，总复杂度 O(m)
			var s = gpHashMap<int, int, MT::custom_hash>();
			for (int x : ps)s[x] = x;
			var find = [&](var find, int x)->int {
				if (s[x] == x)return s[x];
				return s[x] = find(find, s[x]);
				};
			for (const var& [x, y] : es) {
				int e1 = find(find, x);
				int e2 = find(find, y);
				if (e1 != e2)s[e2] = e1;
			}

			// 枚举所有点对，判连通性，O(B ^ 2)
			fa(i, 0, vs(ps))fa(j, i + 1, vs(ps)) {
				int e1 = find(find, ps[i]);
				int e2 = find(find, ps[j]);
				if (e1 == e2)mp[{ps[i], ps[j]}]++;
			}
		}
	}

	int q; cin >> q;
	while (q--) {
		int x, y; cin >> x >> y;
		if (x > y)swap(x, y);

		int ans = 0;

		// 小颜色贡献
		if (mp.find({ x,y }) != mp.end())ans += mp[{x, y}];

		// 大颜色贡献，直接枚举判断 x y 是否连通，最多 O(B)
		fa(i, 0, vs(s)) {
			int e1 = find(find, i, x);
			int e2 = find(find, i, y);
			if (e1 == e2)ans++;
		}
		cout << ans << endl;
	}
	return;
}
